import dask
from dask import delayed

@delayed
def load_file(path):
    import pandas as pd
    return pd.read_csv(path)

@delayed
def clean(df):
    return df.dropna()

@delayed
def summarize(df):
    return df.groupby("category")["sales"].sum()

# Build the task graph
paths = ["file1.csv", "file2.csv", "file3.csv"]
summaries = [summarize(clean(load_file(p))) for p in paths]

# Run all pipelines in parallel
results = dask.compute(*summaries)  # returns a tuple of Pandas Series
